(window.webpackJsonp=window.webpackJsonp||[]).push([[357],{984:function(n,t){n.exports="\x3c!-- \ntitle: 02-Flutter组件\nsort: \n--\x3e \n\n## 组件\n\n### 文本\n\n```dart\nimport 'package:flutter/material.dart';\n\nvoid main() => runApp(MyApp());\n\nclass MyApp extends StatelessWidget {\n  @override\n  Widget build(BuildContext context) {\n    return MaterialApp(\n      title: 'Text widget',\n      home: Scaffold(\n        body: Center(\n            child: Text(\n          '测试~',\n          // 文本位置\n          textAlign: TextAlign.left,\n          // 超出长度的隐藏方式\n          overflow: TextOverflow.ellipsis,\n          // 最长行数\n          maxLines: 1,\n          // 样式\n          style: TextStyle(\n            fontSize: 25.0,\n            color: Color.fromARGB(255, 255, 0, 0),\n            decoration: TextDecoration.underline,\n            decorationStyle: TextDecorationStyle.solid,\n          ),\n        )),\n      ),\n    );\n  }\n}\n\n```\n\n### 容器\n\n- `bottomCenter`:下部居中对齐。\n- `botomLeft`: 下部左对齐。\n- `bottomRight`：下部右对齐。\n- `center`：纵横双向居中对齐。\n- `centerLeft`：纵向居中横向居左对齐。\n- `centerRight`：纵向居中横向居右对齐。\n- `topLeft`：顶部左侧对齐。\n- `topCenter`：顶部居中对齐。\n- `topRight`： 顶部居左对齐。\n\n```dart\nimport 'package:flutter/material.dart';\n\nvoid main() => runApp(MyApp());\n\nclass MyApp extends StatelessWidget {\n  @override\n  Widget build(BuildContext context) {\n    return MaterialApp(\n      title: 'Text widget',\n      home: Scaffold(\n        appBar: AppBar(title: Text('hi~')),\n        body: Center(\n          child: Container(\n            child: Text('Hello Flutter', style: TextStyle(fontSize: 40.0)),\n            alignment: Alignment.center,\n            width: 500.0,\n            height: 400.0,\n            color: Colors.lightBlue, // 颜色\n            // 左上右下\n            padding: const EdgeInsets.fromLTRB(50.0, 50.0, 0.0, 0.0),\n            margin: const EdgeInsets.fromLTRB(50.0, 50.0, 0.0, 0.0),\n          ),\n        ),\n      ),\n    );\n  }\n}\n\n```\n\n#### decoration\n\n```dart\ndecoration: BoxDecoration(\n    // 渐变\n    gradient: const LinearGradient(\n        colors: [Colors.lightBlue, Colors.purple]),\n    // 边框\n    border: Border.all(width: 4.0, color: Colors.green)),\n),\n```\n\n### 图片组件\n\n```dart\nreturn MaterialApp(\n  title: title,\n  home: Scaffold(\n    appBar: AppBar(\n      title: Text(title),\n    ),\n    body: Image.network('https://fzf404.top/public/avatar.jpg'),\n  ),\n);\n```\n\n### 列表组件\n\n```dart\nbody: ListView(\n  children: <Widget>[\n    ListTile(\n      leading: Icon(Icons.access_time),\n      title: Text('access_time'),\n    ),\n    ListTile(\n      leading: Icon(Icons.account_balance),\n      title: Text('account_balance'),\n    ),\n  ],\n),\n```\n\n#### 横向列表\n\n```dart\nbody: Center(\n  child: Container(\n    height: 200.0,\n    child: MyList()\n  ),\n),\n\n// 封装成组件\nclass MyList extends StatelessWidget {\n  @override\n  Widget build(BuildContext context) {\n    return ListView(\n      scrollDirection: Axis.horizontal,\n      children: <Widget>[\n        Container(\n          width: 160.0,\n          color: Colors.red,\n        ),\n        Container(\n          width: 160.0,\n          color: Colors.blue,\n        ),\n        Container(\n          width: 160.0,\n          color: Colors.green,\n        ),\n        Container(\n          width: 160.0,\n          color: Colors.yellow,\n        ),\n        Container(\n          width: 160.0,\n          color: Colors.orange,\n        ),\n      ],\n    );\n  }\n}\n\n```\n\n#### 动态列表\n\n> 传递参数\n\n```dart\nimport 'package:flutter/material.dart';\n\nvoid main() =>\n    runApp(MyApp(items: List<String>.generate(1000, (i) => \"Item $i\")));\n\nclass MyApp extends StatelessWidget {\n  final List<String> items;\n  MyApp({Key key, @required this.items}) : super(key: key);\n  @override\n  Widget build(BuildContext context) {\n    return MaterialApp(\n      title: 'fzf404 & flutter',\n      home: Scaffold(\n        appBar: AppBar(title: Text('List')),\n        body: ListView.builder(\n          itemCount: items.length,\n          itemBuilder: (context, index) {\n            return ListTile(\n              title: Text('${items[index]}'),\n            );\n          },\n        ),\n      ),\n    );\n  }\n}\n\n```\n\n#### 网格列表\n\n```dart\nimport 'package:flutter/material.dart';\n\nvoid main() => runApp(MyApp());\n\nclass MyApp extends StatelessWidget {\n  @override\n  Widget build(BuildContext context) {\n    return MaterialApp(\n      title: 'ListView widget',\n      home: Scaffold(\n        body: GridView.count(\n          padding: const EdgeInsets.all(30),\n          crossAxisSpacing: 30.0,\n          crossAxisCount: 4,\n          children: <Widget>[\n            const Text('1'),\n            const Text('2'),\n            const Text('3'),\n            const Text('4'),\n            const Text('5'),\n            const Text('6'),\n            const Text('7'),\n            const Text('8'),\n          ],\n        ),\n      ),\n    );\n  }\n}\n```\n\n"}}]);